import{_ as t,c as a,o as i,ah as o}from"./chunks/framework.BwTf_eGd.js";const g=JSON.parse('{"title":"Video games","description":"","frontmatter":{},"headers":[],"relativePath":"guides/video-games.md","filePath":"guides/video-games.md","lastUpdated":1748525580000}'),r={name:"guides/video-games.md"};function n(s,e,l,d,c,h){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="video-games" tabindex="-1">Video games <a class="header-anchor" href="#video-games" aria-label="Permalink to “Video games”">​</a></h1><p>A guide about video games integration for Ryot.</p><h2 id="integration-with-igdb" tabindex="-1">Integration with IGDB <a class="header-anchor" href="#integration-with-igdb" aria-label="Permalink to “Integration with IGDB”">​</a></h2><p>Ryot supports tracking video games via <a href="https://www.igdb.com/" target="_blank" rel="noreferrer">IGDB</a>. However, the API is heavily rate limited, so it is not possible to hardcode the API keys in the application (unlike the others).</p><p>You can follow the below steps to obtain your own API keys and enable video game tracking.</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to “Steps”">​</a></h3><ol><li>Create a <a href="https://twitch.tv" target="_blank" rel="noreferrer">Twitch</a> account.</li><li>Open your <a href="https://dev.twitch.tv/console" target="_blank" rel="noreferrer">developer console</a>.</li><li>Click on &quot;Register Your Application&quot; on the dashboard.</li><li>Fill up the details. Any name will suffice but it must be unique. Click on &quot;Create&quot; when you are done.</li><li>You will be guided back to your application dashboard. Click on &quot;Manage&quot; for the application you just created.</li><li>Generate a client secret. Copy the <strong>Client ID</strong> and <strong>Client Secret</strong>.</li><li>Set the <code>VIDEO_GAMES_*</code> environment variables as described in the <a href="./../configuration.html#important-parameters">configuration</a> docs.</li></ol>',7)]))}const u=t(r,[["render",n]]);export{g as __pageData,u as default};
